describe("ChatInput — submit with active slash menu", () => {
  test("Enter key while menu is open submits the raw '/' input", async () => {
    const onSubmit = vi.fn();
    const user = userEvent.setup();

    render(ChatInput, {
      props: {
        onSubmit,
        commands: allCommands,
      },
    });

    const textarea = screen.getByTestId("chat-input");
    await user.type(textarea, "/");

    await waitFor(() => {
      expect(screen.getByTestId("slash-command-menu")).toBeInTheDocument();
    });

    // Enter submits the current trimmed value
    await user.keyboard("{Enter}");

    // "/" is non-empty so onSubmit should be called with "/"
    expect(onSubmit).toHaveBeenCalledWith("/");
  });

  test("after command select, next Enter submits without showing menu again", async () => {
    const onSubmit = vi.fn();
    const user = userEvent.setup();

    render(ChatInput, {
      props: {
        onSubmit,
        commands: allCommands,
      },
    });

    const textarea = screen.getByTestId("chat-input");
    await user.type(textarea, "/");
    await waitFor(() => screen.getByTestId("slash-command-menu"));
    await user.click(screen.getByText(/\/search/));

    await waitFor(() => {
      expect(
        screen.queryByTestId("slash-command-menu"),
      ).not.toBeInTheDocument();
    });

    await user.type(textarea, "kafka{Enter}");

    expect(onSubmit).toHaveBeenCalledOnce();
    expect(onSubmit).toHaveBeenCalledWith("/search kafka");
    expect(screen.queryByTestId("slash-command-menu")).not.toBeInTheDocument();
  });
});

